/**
 * E2E Test Data Factory
 *
 * Provides factories for generating test data for E2E tests.
 * Helps create consistent, unique test data across test runs.
 *
 * @module __tests__/e2e/helpers/test-data.factory
 */

/**
 * Generate a unique string with a prefix
 */
export function uniqueString(prefix: string): string {
  return `${prefix}_${Date.now()}_${Math.random().toString(36).substring(2, 8)}`;
}

/**
 * Generate a unique email address
 */
export function uniqueEmail(prefix = 'test'): string {
  return `${prefix}.${Date.now()}.${Math.random().toString(36).substring(2, 6)}@example.com`;
}

/**
 * User registration data factory
 */
export interface RegisterData {
  email: string;
  password: string;
  passwordConfirm: string;
  firstName: string;
  lastName: string;
  acceptTerms: boolean;
}

export function createRegisterData(overrides: Partial<RegisterData> = {}): RegisterData {
  const password = overrides.password || 'SecureTestPass123!';
  return {
    email: uniqueEmail('e2e'),
    password,
    passwordConfirm: overrides.passwordConfirm || password,
    firstName: 'E2E',
    lastName: 'TestUser',
    acceptTerms: true,
    ...overrides,
  };
}

/**
 * Organization creation data factory
 */
export interface OrganizationData {
  name: string;
  email: string;
  phone?: string;
  address?: string;
  description?: string;
}

export function createOrganizationData(overrides: Partial<OrganizationData> = {}): OrganizationData {
  return {
    name: uniqueString('E2E Org'),
    email: uniqueEmail('org'),
    phone: '+90 555 123 4567',
    address: 'Test Street 123, Istanbul',
    description: 'E2E Test Organization',
    ...overrides,
  };
}

/**
 * Menu creation data factory
 */
export interface MenuData {
  name: string;
  description?: string;
  settings?: {
    showPrices?: boolean;
    enableOrdering?: boolean;
    showAllergens?: boolean;
  };
}

export function createMenuData(overrides: Partial<MenuData> = {}): MenuData {
  return {
    name: uniqueString('E2E Menu'),
    description: 'E2E Test Menu Description',
    settings: {
      showPrices: true,
      enableOrdering: true,
      showAllergens: true,
    },
    ...overrides,
  };
}

/**
 * Category creation data factory
 */
export interface CategoryData {
  menuId: string;
  name: string;
  description?: string;
  isActive?: boolean;
}

export function createCategoryData(menuId: string, overrides: Partial<Omit<CategoryData, 'menuId'>> = {}): CategoryData {
  return {
    menuId,
    name: uniqueString('E2E Category'),
    description: 'E2E Test Category Description',
    isActive: true,
    ...overrides,
  };
}

/**
 * Product creation data factory
 */
export interface ProductVariantData {
  name: string;
  price: number;
  isActive?: boolean;
}

export interface ProductModifierData {
  name: string;
  price: number;
  isActive?: boolean;
}

export interface ProductData {
  categoryId: string;
  name: string;
  description?: string;
  basePrice: number;
  isActive?: boolean;
  isAvailable?: boolean;
  variants?: ProductVariantData[];
  modifiers?: ProductModifierData[];
  allergenIds?: string[];
}

export function createProductData(categoryId: string, overrides: Partial<Omit<ProductData, 'categoryId'>> = {}): ProductData {
  return {
    categoryId,
    name: uniqueString('E2E Product'),
    description: 'E2E Test Product Description',
    basePrice: 150.00,
    isActive: true,
    isAvailable: true,
    variants: [
      { name: 'Regular', price: 150.00, isActive: true },
      { name: 'Large', price: 200.00, isActive: true },
    ],
    modifiers: [
      { name: 'Extra Cheese', price: 20.00, isActive: true },
      { name: 'Bacon', price: 30.00, isActive: true },
    ],
    ...overrides,
  };
}

/**
 * Table creation data factory
 */
export interface TableData {
  number: string;
  capacity: number;
  status?: 'AVAILABLE' | 'OCCUPIED' | 'RESERVED';
  branchId?: string;
  zoneId?: string;
}

export function createTableData(overrides: Partial<TableData> = {}): TableData {
  return {
    number: `T${Date.now().toString().slice(-4)}`,
    capacity: 4,
    status: 'AVAILABLE',
    ...overrides,
  };
}

/**
 * Order item data factory
 */
export interface OrderItemData {
  productId: string;
  quantity: number;
  variantId?: string;
  modifiers?: Array<{ id: string; quantity: number }>;
  notes?: string;
}

export function createOrderItemData(productId: string, overrides: Partial<Omit<OrderItemData, 'productId'>> = {}): OrderItemData {
  return {
    productId,
    quantity: 1,
    ...overrides,
  };
}

/**
 * Order creation data factory
 */
export interface OrderData {
  type: 'DINE_IN' | 'TAKEAWAY' | 'DELIVERY';
  tableId?: string;
  customerId?: string;
  items: OrderItemData[];
  notes?: string;
}

export function createOrderData(items: OrderItemData[], overrides: Partial<Omit<OrderData, 'items'>> = {}): OrderData {
  return {
    type: 'DINE_IN',
    items,
    notes: 'E2E Test Order',
    ...overrides,
  };
}
